{
  "activities": [
    {
      "type": "activity",
      "title": "Constructing a Square with Baudhayana's Sulbasutras Method",
      "unit_name": "UNIT IV: GEOMETRY",
      "chapter_name": "GEOMETRY",
      "details": "Students construct a square with a given side as described in the Baudhayana's Sulbasutras to understand ancient geometric constructions."
    },
    {
      "type": "activity",
      "title": "Square Root Spiral Construction",
      "unit_name": "UNIT I: NUMBER SYSTEM (Inferred from context)",
      "chapter_name": "Number System",
      "details": "Construct the square root spiral to represent rational and irrational numbers through visual models."
    },
    {
      "type": "activity",
      "title": "Tower of Hanoi Puzzle Solving",
      "unit_name": "UNIT II: ALGEBRA",
      "chapter_name": "ALGEBRA",
      "details": "Solve the Tower of Hanoi puzzle to visualize Geometric Progressions and apply computational thinking."
    },
    {
      "type": "activity",
      "title": "Visualising Algebraic Identities with Models",
      "unit_name": "UNIT II: ALGEBRA",
      "chapter_name": "ALGEBRA",
      "details": "Use geometric models, algebra tiles (with and without), or paper manipulation to visualise factorisation of quadratic expressions."
    },
    {
      "type": "activity",
      "title": "Floor Plan Grid Representation",
      "unit_name": "UNIT III: COORDINATE GEOMETRY",
      "chapter_name": "COORDINATE GEOMETRY",
      "details": "Represent a floor plan on a grid using coordinates to specify locations and positions."
    },
    {
      "type": "activity",
      "title": "Geometric Constructions with Paper Manipulation",
      "unit_name": "UNIT IV: GEOMETRY",
      "chapter_name": "GEOMETRY",
      "details": "Engage in drawing, measurement and paper manipulation activities to discover geometric patterns involving triangles and 4-gons."
    },
    {
      "type": "activity",
      "title": "Cultural Motifs Analysis (Dharmachakra/Ashoka Chakra)",
      "unit_name": "UNIT IV: GEOMETRY",
      "chapter_name": "GEOMETRY",
      "details": "Identify cultural motifs involving circles, such as the Dharmachakra and Ashoka Chakra."
    },
    {
      "type": "activity",
      "title": "Real-world Circle Applications Study",
      "unit_name": "UNIT IV: GEOMETRY",
      "chapter_name": "GEOMETRY",
      "details": "Investigate how circular wheels have influenced transport, farming, building, and technology."
    },
    {
      "type": "activity",
      "title": "Data Collection and Graphical Representation",
      "unit_name": "UNIT VI: STATISTICS AND PROBABILITY",
      "chapter_name": "STATISTICS AND PROBABILITY",
      "details": "Collect, organise, visualise data to answer a statistical investigative question using stacked bar graphs."
    },
    {
      "type": "activity",
      "title": "Empirical Probability Experiments",
      "unit_name": "UNIT VI: STATISTICS AND PROBABILITY (Continued)",
      "chapter_name": "STATISTICS AND PROBABILITY (Continued)",
      "details": "Perform experiments to estimate the empirical probability of events and represent them using tree diagrams."
    }
  ],
  "projects": [
    {
      "title": "Historical Approximations of Pi Research",
      "unit_name": "UNIT V: MENSURATION",
      "chapter_name": "Surface Area and Volume",
      "details": "Research historical approximations to π (Archimedes, Aryabhata, Zu Chongzhi) and explain ancient methods for circle area."
    },
    {
      "title": "Squaring a Rectangle Investigation",
      "unit_name": "UNIT V: MENSURATION",
      "chapter_name": "Surface Area and Volume",
      "details": "Investigate the proof of 'squaring a rectangle' from Baudhayana's Sulbasutras."
    },
    {
      "title": "Brahmagupta's Formula Derivation Project",
      "unit_name": "UNIT V: MENSURATION",
      "chapter_name": "Surface Area and Volume",
      "details": "Derive Brahmagupta's formula for the area of a cyclic 4-gon and explain its relationship to Heron's formula."
    },
    {
      "title": "3-D Shape Surface Area and Volume Analysis",
      "unit_name": "UNIT V: MENSURATION (Continued)",
      "chapter_name": "Surface Area and Volume (Continued)",
      "details": "Systematically calculate and compare surface areas and volumes of 3-D shapes by varying dimensions."
    },
    {
      "title": "Weighted Average Application Study",
      "unit_name": "UNIT VI: STATISTICS AND PROBABILITY",
      "chapter_name": "STATISTICS AND PROBABILITY",
      "details": "Apply weighted average concepts in different real-life settings and analyze statistical data."
    }
  ],
  "practicals": [
    {
      "title": "Mathematics Laboratory Activities (Prescribed Books)",
      "unit_name": "UNIT I: NUMBER SYSTEM",
      "chapter_name": "Number System",
      "details": "Lab activities from prescribed books including constructing square root spiral and representing rational/irrational numbers."
    },
    {
      "title": "Geometric Constructions Lab (Euclid's Axioms)",
      "unit_name": "UNIT IV: GEOMETRY",
      "chapter_name": "GEOMETRY",
      "details": "Construct bisectors of line segments, angles and their bisectors, triangles, and other polygons satisfying given constraints."
    },
    {
      "title": "Circumcircle Construction Lab",
      "unit_name": "UNIT IV: GEOMETRY",
      "chapter_name": "GEOMETRY",
      "details": "Construct the circumcircle and circumcentre of a triangle using geometric tools."
    },
    {
      "title": "Coordinate Geometry Distance Calculation Lab",
      "unit_name": "UNIT III: COORDINATE GEOMETRY",
      "chapter_name": "COORDINATE GEOMETRY",
      "details": "Compute the distance between two points and determine if three points lie in a straight line using coordinates."
    },
    {
      "title": "Area Calculation Lab (Heron's Formula)",
      "unit_name": "UNIT V: MENSURATION",
      "chapter_name": "Surface Area and Volume",
      "details": "Compute the area of triangles from sides using Heron's formula."
    },
    {
      "title": "3-D Shape Modelling Lab",
      "unit_name": "UNIT V: MENSURATION (Continued)",
      "chapter_name": "Surface Area and Volume (Continued)",
      "details": "Visualise 2D representations of 3D objects to solve problems involving surface area and volume."
    },
    {
      "title": "Probability Simulation Lab",
      "unit_name": "UNIT VI: STATISTICS AND PROBABILITY (Continued)",
      "chapter_name": "STATISTICS AND PROBABILITY (Continued)",
      "details": "Use computational thinking strategies like simulation to model random experiments and estimate probabilities."
    }
  ]
}
